    public function handle_order_book($client, $message) {
        //
        // {
        //   "channel" => "book",
        //   "data" => {
        //     "l" => array(
        //       array(
        //         array(
        //           "a" => "37.86",
        //           "n" => 4,
        //           "p" => "157.47"
        //         ),
        //         // ... other aggegated bid $levels
        //       ),
        //       array(
        //         array(
        //           "a" => "12.7",
        //           "n" => 2,
        //           "p" => "157.49"
        //         ),
        //         array(
        //           "a" => "44.45",
        //           "n" => 3,
        //           "p" => "157.5"
        //         ),
        //         // ... other aggregated ask $levels
        //       )
        //     ),
        //     "s" => "SOL",
        //     "t" => 1749051881187,
        //     "li" => 1559885104 // sequence id - last order id
        //   }
        // }
        //
        $entry = $this->safe_dict($message, 'data', array());
        $marketId = $this->safe_string($entry, 's');
        $market = $this->safe_market($marketId);
        $symbol = $market['symbol'];
        $levels = $this->safe_list($entry, 'l', array());
        $result = array(
            'bids' => $this->safe_list($levels, 0, array()),
            'asks' => $this->safe_list($levels, 1, array()),
        );
        $timestamp = $this->safe_integer($entry, 't');
        $snapshot = $this->parse_order_book($result, $symbol, $timestamp, 'bids', 'asks', 'p', 'a');
        $nonce = $this->safe_integer($entry, 'li');
        if ($nonce) {
            $snapshot['nonce'] = $nonce;
        }
        if (!(is_array($this->orderbooks) && array_key_exists($symbol, $this->orderbooks))) {
            $ob = $this->order_book($snapshot);
            $this->orderbooks[$symbol] = $ob;
        }
        $orderbook = $this->orderbooks[$symbol];
        $orderbook->reset ($snapshot);
        $messageHash = 'orderbook:' . $symbol;
        $client->resolve ($orderbook, $messageHash);
    }

