    public function handle_ws_tickers(Client $client, $message) {
        //
        // {
        //     "channel" => "prices",
        //     "data" => array(
        //         {
        //             "funding" => "0.0000125",
        //             "mark" => "105473",
        //             "mid" => "105476",
        //             "next_funding" => "0.0000125",
        //             "open_interest" => "0.00524",
        //             "oracle" => "105473",
        //             "symbol" => "BTC",
        //             "timestamp" => 1749051612681,
        //             "volume_24h" => "63265.87522",
        //             "yesterday_price" => "955476"
        //         }
        //         // ... other $symbol prices
        //     ),
        // }
        //
        $parsedTickers = array();
        $data = $this->safe_list($message, 'data', array());
        for ($i = 0; $i < count($data); $i++) {
            $info = $data[$i];
            $marketId = $this->safe_string($info, 'symbol');
            $market = $this->safe_market($marketId);
            $symbol = $market['symbol'];
            $ticker = $this->parse_ws_ticker($info, $market);
            $this->tickers[$symbol] = $ticker;
            $parsedTickers[] = $ticker;
        }
        $tickers = $this->index_by($parsedTickers, 'symbol');
        $client->resolve ($tickers, 'tickers');
        return true;
    }

    public function parse_ws_ticker($rawTicker, ?array $market = null): array {
        return $this->parse_ticker($rawTicker, $market);
    }

    public function handle_my_trades(Client $client, $message) {
        //
        // {
        //   "channel" => "account_trades",
        //   "data" => array(
        //     {
        //       "h" => 80063441, // history id
        //       "i" => 1559912767, // oid
        //       "I" => null, // cloid
        //       "u" => "BrZp5bidJ3WUvceSq7X78bhjTfZXeezzGvGEV4hAYKTa", // account address
        //       "s" => "BTC",  // $symbol
        //       "p" => "89477", // price
        //       "o" => "89505", // entry price
        //       "a" => "0.00036", // amount
        //       "te" => "fulfill_taker",
        //       "ts" => "close_long",
        //       "tc" => "normal", // trade type
        //       "f" => "0.012885", // fee
        //       "n" => "-0.022965", // pnl
        //       "t" => 1765018588190,
        //       "li" => 1559912767
        //     }
        //   )
        // }
        //
        if ($this->myTrades === null) {
            $limit = $this->safe_integer($this->options, 'tradesLimit', 1000);
            $this->myTrades = new ArrayCacheBySymbolById ($limit);
        }
        $trades = $this->myTrades;
        $symbols = array();
        $data = $this->safe_list($message, 'data', array());
        $dataLength = count($data);
        if ($dataLength === 0) {
            return;
        }
        for ($i = 0; $i < count($data); $i++) {
            $rawTrade = $data[$i];
            $parsed = $this->parse_ws_trade($rawTrade);
            $symbol = $parsed['symbol'];
            $symbols[$symbol] = true;
            $trades->append ($parsed);
        }
        $keys = is_array($symbols) ? array_keys($symbols) : array();
        for ($i = 0; $i < count($keys); $i++) {
            $currentMessageHash = 'myTrades:' . $keys[$i];
            $client->resolve ($trades, $currentMessageHash);
        }
        // non-$symbol specific
        $messageHash = 'myTrades';
        $client->resolve ($trades, $messageHash);
    }

