    public function handle_trades(Client $client, $message) {
        //
        // {
        //   "channel" => "trades",
        //   "data" => array(
        //     {
        //       "h" => 80062522,
        //       "s" => "BTC",
        //       "a" => "0.00001",
        //       "p" => "89471",
        //       "d" => "close_short",
        //       "tc" => "normal",
        //       "t" => 1765018379085,
        //       "li" => 1559885104
        //     }
        //   )
        // }
        //
        $entry = $this->safe_list($message, 'data', array());
        $first = $this->safe_dict($entry, 0, array());
        $marketId = $this->safe_string($first, 's');
        $market = $this->safe_market($marketId);
        $symbol = $market['symbol'];
        if (!(is_array($this->trades) && array_key_exists($symbol, $this->trades))) {
            $limit = $this->safe_integer($this->options, 'tradesLimit', 1000);
            $stored = new ArrayCache ($limit);
            $this->trades[$symbol] = $stored;
        }
        $trades = $this->trades[$symbol];
        for ($i = 0; $i < count($entry); $i++) {
            $data = $this->safe_dict($entry, $i);
            $trade = $this->parse_ws_trade($data);
            $trades->append ($trade);
        }
        $messageHash = 'trade:' . $symbol;
        $client->resolve ($trades, $messageHash);
    }

    public function parse_ws_trade(array $trade, ?array $market = null): array {
        //
        // fetchMyTrades
        //
        //    {
        //       "h" => 80063441, // history $id
        //       "i" => 1559912767, // oid
        //       "I" => null, // cloid
        //       "u" => "BrZp5bidJ3WUvceSq7X78bhjTfZXeezzGvGEV4hAYKTa", // account address
        //       "s" => "BTC",  // $symbol
        //       "p" => "89477", // $price
        //       "o" => "89505", // entry $price
        //       "a" => "0.00036", // $amount
        //       "te" => "fulfill_taker",
        //       "ts" => "close_long",
        //       "tc" => "normal", // $trade type
        //       "f" => "0.012885", // $fee
        //       "n" => "-0.022965", // pnl
        //       "t" => 1765018588190,
        //       "li" => 1559912767
        //     }
        //
        // fetchTrades
        //
        //     {
        //       "h" => 80062522,
        //       "s" => "BTC",
        //       "a" => "0.00001",
        //       "p" => "89471",
        //       "d" => "close_short",
        //       "tc" => "normal",
        //       "t" => 1765018379085,
        //       "li" => 1559885104
        //     }
        //
        $timestamp = $this->safe_integer($trade, 't');
        $price = $this->safe_string($trade, 'p');
        $amount = $this->safe_string($trade, 'a');
        $marketId = $this->safe_string($trade, 's');
        $market = $this->safe_market($marketId, $market);
        $symbol = $market['symbol'];
        $id = $this->safe_string($trade, 'h');
        $fee = $this->safe_string($trade, 'f');
        $side = $this->safe_string_2($trade, 'ts', 'd');
        if ($side === 'open_long') {
            $side = 'buy';
        } elseif ($side === 'close_long') {
            $side = 'sell';
        } elseif ($side === 'open_short') {
            $side = 'sell';
        } elseif ($side === 'close_short') {
            $side = 'buy';
        }
        $eventType = $this->safe_string($trade, 'te');
        $takerOrMaker = null;
        if ($eventType !== null) {
            $takerOrMaker = ($eventType === 'fulfill_maker') ? 'maker' : 'taker';
        }
        $orderId = $this->safe_string($trade, 'i');
        // public trades have no $orderId
        if ($orderId === null) {
            $takerOrMaker = null;
        }
        return $this->safe_trade(array(
            'info' => $trade,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'symbol' => $symbol,
            'id' => $id,
            'order' => $this->safe_string($trade, 'i'),
            'type' => null,
            'side' => $side,
            'takerOrMaker' => $takerOrMaker,
            'price' => $price,
            'amount' => $amount,
            'cost' => null,
            'fee' => array( 'cost' => $fee, 'currency' => 'USDC' ),
        ), $market);
    }

    public function watch_ohlcv(string $symbol, string $timeframe = '1m', ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $timeframe, $since, $limit, $params) {
            /**
             * watches historical candlestick data containing the open, high, low, close price, and the volume of a $market
             *
             * @see https://docs.pacifica.fi/api-documentation/api/websocket/subscriptions/candle
             *
             * @param {string} $symbol unified $symbol of the $market to fetch OHLCV data for
             * @param {string} $timeframe the length of time each candle represents
             * @param {int} [$since] timestamp in ms of the earliest candle to fetch
             * @param {int} [$limit] the maximum amount of candles to fetch
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {int[][]} A list of candles ordered, open, high, low, close, volume
             */
            Async\await($this->load_markets());
            $market = $this->market($symbol);
            $symbol = $market['symbol'];
            $isTestnet = $this->isSandboxModeEnabled;
            $parsedTf = $this->safe_string($this->timeframes, $timeframe, $timeframe);
            $urlKey = ($isTestnet) ? 'test' : 'api';
            $url = $this->urls[$urlKey]['ws']['public'];
            $request = array(
                'method' => 'subscribe',
                'params' => array(
                    'source' => 'candle',
                    'symbol' => $market['id'],
                    'interval' => $parsedTf,
                ),
            );
            $messageHash = 'candles:' . $parsedTf . ':' . $symbol;
            $message = $this->extend($request, $params);
            $ohlcv = Async\await($this->watch($url, $messageHash, $message, $messageHash));
            if ($this->newUpdates) {
                $limit = $ohlcv->getLimit ($symbol, $limit);
            }
            return $this->filter_by_since_limit($ohlcv, $since, $limit, 0, true);
        }) ();
    }

