    public function handle_ohlcv(Client $client, $message) {
        //
        // {
        //   "channel" => "candle",
        //   "data" => {
        //     "t" => 1749052260000,
        //     "T" => 1749052320000,
        //     "s" => "SOL",
        //     "i" => "1m",
        //     "o" => "157.3",
        //     "c" => "157.32",
        //     "h" => "157.32",
        //     "l" => "157.3",
        //     "v" => "1.22",
        //     "n" => 8
        //   }
        // }
        //
        $data = $this->safe_dict($message, 'data', array());
        $marketId = $this->safe_string($data, 's');
        $market = $this->safe_market($marketId);
        $symbol = $market['symbol'];
        $timeframe = $this->safe_string($data, 'i');
        if (!(is_array($this->ohlcvs) && array_key_exists($symbol, $this->ohlcvs))) {
            $this->ohlcvs[$symbol] = array();
        }
        if (!(is_array($this->ohlcvs[$symbol]) && array_key_exists($timeframe, $this->ohlcvs[$symbol]))) {
            $limit = $this->safe_integer($this->options, 'OHLCVLimit', 1000);
            $stored = new ArrayCacheByTimestamp ($limit);
            $this->ohlcvs[$symbol][$timeframe] = $stored;
        }
        $ohlcv = $this->ohlcvs[$symbol][$timeframe];
        $parsed = $this->parse_ohlcv($data);
        $ohlcv->append ($parsed);
        $messageHash = 'candles:' . $timeframe . ':' . $symbol;
        $client->resolve ($ohlcv, $messageHash);
    }

    public function watch_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $since, $limit, $params) {
            /**
             * watches information on multiple $orders made by the user
             *
             * @see https://docs.pacifica.fi/api-documentation/api/websocket/subscriptions/account-order-updates
             *
             * @param {string} $symbol unified $market $symbol of the $market $orders were made in
             * @param {int} [$since] the earliest time in ms to fetch $orders for
             * @param {int} [$limit] the maximum number of order structures to retrieve
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string|null} [$params->account] will default to options' walletAddress if not provided
             * @return {array[]} a list of ~@link https://docs.ccxt.com/?id=order-structure order structures~
             */
            Async\await($this->load_markets());
            $userAddress = null;
            list($userAddress, $params) = $this->handleOriginAndSingleAddress ('watchOrders', $params);
            $market = null;
            $messageHash = 'order';
            if ($symbol !== null) {
                $market = $this->market($symbol);
                $symbol = $market['symbol'];
                $messageHash = $messageHash . ':' . $symbol;
            }
            $isTestnet = $this->isSandboxModeEnabled;
            $urlKey = ($isTestnet) ? 'test' : 'api';
            $url = $this->urls[$urlKey]['ws']['public'];
            $request = array(
                'method' => 'subscribe',
                'params' => array(
                    'source' => 'account_order_updates',
                    'account' => $userAddress,
                ),
            );
            $message = $this->extend($request, $params);
            $orders = Async\await($this->watch($url, $messageHash, $message, $messageHash));
            if ($this->newUpdates) {
                $limit = $orders->getLimit ($symbol, $limit);
            }
            return $this->filter_by_symbol_since_limit($orders, $symbol, $since, $limit, true);
        }) ();
    }

    public function un_watch_orders(?string $symbol = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $params) {
            /**
             * unWatches information on multiple orders made by the user
             *
             * @see https://docs.pacifica.fi/api-documentation/api/websocket/subscriptions/account-order-updates
             *
             * @param {string} $symbol unified market $symbol of the market orders were made in
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string|null} [$params->account] will default to options' walletAddress if not provided
             * @return {array[]} a list of ~@link https://docs.ccxt.com/#/?id=order-structure order structures~
             */
            Async\await($this->load_markets());
            if ($symbol !== null) {
                throw new NotSupported($this->id . ' unWatchOrders() does not support a $symbol argument, unWatch from all markets only');
            }
            $messageHash = 'unsubscribe:order';
            $isTestnet = $this->isSandboxModeEnabled;
            $urlKey = ($isTestnet) ? 'test' : 'api';
            $url = $this->urls[$urlKey]['ws']['public'];
            $userAddress = null;
            list($userAddress, $params) = $this->handleOriginAndSingleAddress ('unWatchOrders', $params);
            $request = array(
                'method' => 'unsubscribe',
                'params' => array(
                    'source' => 'account_order_updates',
                    'account' => $userAddress,
                ),
            );
            $message = $this->extend($request, $params);
            return Async\await($this->watch($url, $messageHash, $message, $messageHash));
        }) ();
    }

    public function handle_order(Client $client, $message) {
        // not snapshot, only updates
        // {
        //   "channel" => "account_order_updates",
        //   "data" => array(
        //     {
        //       "i" => 1559665358,
        //       "I" => null,
        //       "u" => "BrZp5bidJ3WUvceSq7X78bhjTfZXeezzGvGEV4hAYKTa",
        //       "s" => "BTC",
        //       "d" => "bid",
        //       "p" => "89501",
        //       "ip" => "89501",
        //       "lp" => "89501",
        //       "a" => "0.00012",
        //       "f" => "0.00012",
        //       "oe" => "fulfill_limit",
        //       "os" => "filled",
        //       "ot" => "limit",
        //       "sp" => null,
        //       "si" => null,
        //       "r" => false,
        //       "ct" => 1765017049008,
        //       "ut" => 1765017219639,
        //       "li" => 1559696133
        //     }
        //   )
        // }
        $data = $this->safe_list($message, 'data', array());
        if ($this->orders === null) {
            $limit = $this->safe_integer($this->options, 'ordersLimit', 1000);
            $this->orders = new ArrayCacheBySymbolById ($limit);
        }
        $dataLength = count($data);
        if ($dataLength === 0) {
            return;
        }
        $stored = $this->orders;
        $messageHash = 'order';
        $marketSymbols = array();
        for ($i = 0; $i < count($data); $i++) {
            $rawOrder = $data[$i];
            $order = $this->parse_order($rawOrder);
            $stored->append ($order);
            $symbol = $this->safe_string($order, 'symbol');
            $marketSymbols[$symbol] = true;
        }
        $keys = is_array($marketSymbols) ? array_keys($marketSymbols) : array();
        for ($i = 0; $i < count($keys); $i++) {
            $symbol = $keys[$i];
            $innerMessageHash = $messageHash . ':' . $symbol;
            $client->resolve ($stored, $innerMessageHash);
        }
        $client->resolve ($stored, $messageHash);
    }

    public function handle_error_message(Client $client, $message): Bool {
        //
        // 'rl' key is present only when a rate-limited API key is used
        // array("id":"64107e37-a999-4b90-a3cf-b4322ae110d9","type":"cancel_order","code":420,"err":"Failed to cancel order","t":1769474703073,"rl":array("r":1245,"q":1250,"t":56))
        //
        $error = $this->safe_string($message, 'err', '');
        $postType = $this->safe_string($message, 'type', '');
        $data = $this->safe_dict($message, 'data', array());
        $id = $this->safe_string($message, 'id');
        if ($id === null) {
            $id = $this->safe_string($data, 'id');
        }
        try {
            $this->handle_errors(0, $error, '', $postType, $this->options['ws']['options']['headers'], $this->json($data), $message, array(), array());
        } catch (Exception $e) {
            $client->reject ($e, $id);
            return true;
        }
        return false;
    }

    public function handle_order_book_unsubscription(Client $client, array $subscription) {
        $marketId = $this->safe_string_2($subscription, 'symbol', 's');
        $market = $this->safe_market($marketId);
        $symbol = $market['symbol'];
        $subMessageHash = 'orderbook:' . $symbol;
        $messageHash = 'unsubscribe:' . $subMessageHash;
        $this->clean_unsubscription($client, $subMessageHash, $messageHash);
        if (is_array($this->orderbooks) && array_key_exists($symbol, $this->orderbooks)) {
            unset($this->orderbooks[$symbol]);
        }
    }

    public function handle_trades_unsubscription(Client $client, array $subscription) {
        $marketId = $this->safe_string_2($subscription, 'symbol', 's');
        $market = $this->safe_market($marketId);
        $symbol = $market['symbol'];
        $subMessageHash = 'trade:' . $symbol;
        $messageHash = 'unsubscribe:' . $subMessageHash;
        $this->clean_unsubscription($client, $subMessageHash, $messageHash);
        if (is_array($this->trades) && array_key_exists($symbol, $this->trades)) {
            unset($this->trades[$symbol]);
        }
    }

    public function handle_tickers_unsubscription(Client $client, array $subscription) {
        $subMessageHash = 'tickers';
        $messageHash = 'unsubscribe:' . $subMessageHash;
        $this->clean_unsubscription($client, $subMessageHash, $messageHash);
        $symbols = is_array($this->tickers) ? array_keys($this->tickers) : array();
        for ($i = 0; $i < count($symbols); $i++) {
            unset($this->tickers[$symbols[$i]]);
        }
    }

    public function handle_ohlcv_unsubscription(Client $client, array $subscription) {
        $marketId = $this->safe_string_2($subscription, 'symbol', 's');
        $market = $this->safe_market($marketId);
        $symbol = $market['symbol'];
        $interval = $this->safe_string($subscription, 'interval');
        $timeframe = $this->find_timeframe($interval);
        $subMessageHash = 'candles:' . $timeframe . ':' . $symbol;
        $messageHash = 'unsubscribe:' . $subMessageHash;
        $this->clean_unsubscription($client, $subMessageHash, $messageHash);
        if (is_array($this->ohlcvs) && array_key_exists($symbol, $this->ohlcvs)) {
            if (is_array($this->ohlcvs[$symbol]) && array_key_exists($timeframe, $this->ohlcvs[$symbol])) {
                unset($this->ohlcvs[$symbol][$timeframe]);
            }
        }
    }

    public function handle_order_unsubscription(Client $client, array $subscription) {
        $subHash = 'order';
        $unSubHash = 'unsubscribe:' . $subHash;
        $this->clean_unsubscription($client, $subHash, $unSubHash, true);
        $topicStructure = array(
            'topic' => 'orders',
        );
        $this->clean_cache($topicStructure);
    }

    public function handle_my_trades_unsubscription(Client $client, array $subscription) {
        $subHash = 'myTrades';
        $unSubHash = 'unsubscribe:' . $subHash;
        $this->clean_unsubscription($client, $subHash, $unSubHash, true);
        $topicStructure = array(
            'topic' => 'myTrades',
        );
        $this->clean_cache($topicStructure);
    }

    public function handle_subscription_response(Client $client, $message) {
        //  {
        //      "channel" => "subscribe",
        //      "data" => {
        //          "source" => "book",
        //          "symbol" => "SOL",
        //          "agg_level" => 1
        //      }
        //  }
        //
        //  {
        //      "channel" => "unsubscribe",
        //      "data" => {
        //          "source" => "book",
        //          "symbol" => "SOL",
        //          "agg_level" => 1
        //      }
        //  }
        //
        $data = $this->safe_dict($message, 'data', array());
        $method = $this->safe_string($message, 'channel');
        if ($method === 'unsubscribe') {
            $subscription = $this->safe_dict($data, 'data', array());
            $type = $this->safe_string($subscription, 'source');
            if ($type === 'book') {
                $this->handle_order_book_unsubscription($client, $subscription);
            } elseif ($type === 'trades') {
                $this->handle_trades_unsubscription($client, $subscription);
            } elseif ($type === 'prices') {
                $this->handle_tickers_unsubscription($client, $subscription);
            } elseif ($type === 'candle') {
                $this->handle_ohlcv_unsubscription($client, $subscription);
            } elseif ($type === 'account_order_updates') {
                $this->handle_order_unsubscription($client, $subscription);
            } elseif ($type === 'account_trades') {
                $this->handle_my_trades_unsubscription($client, $subscription);
            }
        }
    }

    public function handle_message(Client $client, $message) {
        //
        // {
        //     "channel":"subscribe",
        //     "data":{
        //        "method":"unsubscribe",
        //        "subscription":{
        //           "type":"l2Book",
        //           "coin":"BTC",
        //           "nSigFigs":5,
        //           "mantissa":null
        //        }
        //     }
        // }
        //
        if ($this->handle_error_message($client, $message)) {
            return;
        }
        $postType = $this->safe_string($message, 'type', null);
        $topic = $this->safe_string($message, 'channel', '');
        $methods = array(
            'pong' => array($this, 'handle_pong'),
            'trades' => array($this, 'handle_trades'),
            'book' => array($this, 'handle_order_book'),
            'candle' => array($this, 'handle_ohlcv'),
            'account_order_updates' => array($this, 'handle_order'),
            'account_trades' => array($this, 'handle_my_trades'),
            'prices' => array($this, 'handle_ws_tickers'),
            'subscribe' => array($this, 'handle_subscription_response'),
            'unsubscribe' => array($this, 'handle_subscription_response'),
        );
        $exacMethod = $this->safe_value($methods, $topic);
        if ($exacMethod !== null) {
            $exacMethod($client, $message);
            return;
        }
        if ($postType !== null) {
            $this->handle_ws_post($client, $message);
            return;
        }
        $keys = is_array($methods) ? array_keys($methods) : array();
        for ($i = 0; $i < count($keys); $i++) {
            $key = $keys[$i];
            if (mb_strpos($topic, $keys[$i]) !== false) {
                $method = $methods[$key];
                $method($client, $message);
                return;
            }
        }
    }

    public function ping(Client $client) {
        return array(
            'method' => 'ping',
        );
    }

    public function handle_pong(Client $client, $message) {
        //
        //   {
        //       "channel" => "pong"
        //   }
        //
        $client->lastPong = $this->safe_integer($message, 'pong', $this->milliseconds());
        return $message;
    }

    public function request_id(): string {
        return $this->uuid(); // uuid v4
    }

    public function wrap_as_post_action(string $operationType, array $request): array {
        if ($operationType === null) {
            throw new ArgumentsRequired($this->id . 'postAction() requires a "operationType" argument!');
        }
        $requestId = $this->request_id();
        $payload = array(
            'id' => $requestId,
            'params' => array(),
        );
        $payload['params'][$operationType] = $request;
        return $payload;
    }

